    locationLabel: "🗺️ Location Link:",
    locationButton: "View on Google Maps",
    readNote: "Read a Small Note 🙏",
    hideNote: "Hide Note 🙏",
    noteTitle: "A Small Note:",
    noteContent:
      "Since we may not be able to reach everyone personally to hand over a physical card, please accept this digital invitation as a sincere and heartfelt request for your presence. We look forward to seeing you there!",
